query:
ALTER TABLE `customers` 
  CHANGE COLUMN `sevdesk_contact_id` `sevdesk_id` varchar(64),
  CHANGE COLUMN `isActive` `is_active` boolean NOT NULL DEFAULT true;

ALTER TABLE `lead_sources`
  CHANGE COLUMN `monthlyCost` `monthly_cost` decimal(10,2),
  CHANGE COLUMN `isActive` `is_active` boolean NOT NULL DEFAULT true;

ALTER TABLE `suppliers`
  CHANGE COLUMN `isActive` `is_active` boolean NOT NULL DEFAULT true;

ALTER TABLE `knowledge_entries`
  CHANGE COLUMN `isActive` `is_active` boolean NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS `use_count` int DEFAULT 0;

ALTER TABLE `image_library`
  ADD COLUMN IF NOT EXISTS `use_count` int DEFAULT 0;

ALTER TABLE `project_items`
  CHANGE COLUMN `technology` `technique` enum('3d_print','cnc','painting','cad_work','model_making','assembly','other') DEFAULT 'other',
  CHANGE COLUMN `ek_price` `unit_ek` decimal(12,2) DEFAULT 0,
  CHANGE COLUMN `vk_price` `unit_vk` decimal(12,2) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS `total_ek` decimal(12,2) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS `total_vk` decimal(12,2) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS `description` text,
  ADD COLUMN IF NOT EXISTS `sort_order` int DEFAULT 0;

ALTER TABLE `consultation_entries`
  CHANGE COLUMN `type` `type` enum('material_advice','process_advice','technical_analysis','offer_discussion','general','other') NOT NULL DEFAULT 'general';

ALTER TABLE `materials_library`
  ADD COLUMN IF NOT EXISTS `disadvantages` text,
  ADD COLUMN IF NOT EXISTS `tags` json;

ALTER TABLE `rfq_responses`
  ADD COLUMN IF NOT EXISTS `updatedAt` timestamp DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP;

ALTER TABLE `projects`
  CHANGE COLUMN `title` `title` varchar(255) NOT NULL;

